parameters.jsonSchema:
{
  "title": "Client Onboarding Event",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "eventType",
    "version",
    "source",
    "createdAt",
    "payload"
  ],
  "properties": {
    "eventType": {
      "type": "string",
      "const": "CLIENT_ONBOARDING_RECEIVED"
    },
    "version": {
      "type": "string",
      "const": "1.0"
    },
    "source": {
      "type": "string",
      "const": "n8n-client-onboarding"
    },
    "createdAt": {
      "type": "string",
      "format": "date-time"
    },
    "payload": {
      "$ref": "#/$defs/ClientOnboardingPayload"
    }
  },
  "$defs": {
    "ClientOnboardingPayload": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "clientId",
        "clientName",
        "email",
        "serviceType",
        "taxYear",
        "documents"
      ],
      "properties": {
        "clientId": {
          "type": "string",
          "minLength": 1
        },
        "clientName": {
          "type": "string",
          "minLength": 1
        },
        "email": {
          "type": "string",
          "format": "email"
        },
        "serviceType": {
          "type": "string",
          "enum": [
            "Individual Tax Return",
            "Company Tax Return",
            "SMSF",
            "BAS",
            "Bookkeeping"
          ]
        },
        "taxYear": {
          "type": "integer",
          "minimum": 2000,
          "maximum": 2100
        },
        "documents": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "documentType",
              "fileName"
            ],
            "properties": {
              "documentType": {
                "type": "string",
                "minLength": 1
              },
              "fileName": {
                "type": "string",
                "minLength": 1
              }
            }
          }
        }
      }
    }
  }
}

